        text: "Welcome back, smith! I've been keeping the heavy equipment in the back. Open up my catalog and see if something catches your eye.",
        viewMode: 'INTERACTION'
    },
    FURNACE_GUIDE: {
        speaker: "Garrick",
        text: "There it is! A fine piece of engineering. It's not as grand as your old one, but it'll bring the fire back to your lineage in no time.",
        viewMode: 'CATALOG'
    },
    OPEN_SHOPPING_CART: {
        speaker: "Garrick",
        text: "Going to settle the bill? Open your cart on the right. I like my ledgers clean, and I'm sure you do too.",
        viewMode: 'CATALOG'
    },
    CLOSE_SHOPPING_CART: {
