            </button>
          </div>
        </div>
      )}

      {/* Conceptual Counter Shadow (Bottom) */}
      <div className="absolute bottom-0 w-full h-[35dvh] md:h-64 z-20 pointer-events-none bg-gradient-to-t from-black/90 to-transparent"></div>
